Execute the following Node.js simulation that mimics both patterns:

```js
// Simulate $http-style .success/.error (non-standard)
function fakeHttpLegacy() {
  const p = Promise.resolve({ data: {id:1}, status: 200, statusText: 'OK', headers: {}, config: {} });
  p.success = function(fn) { p.then(r => fn(r.data, r.status, r.headers, r.config)); return p; };
  p.error = function(fn) { p.catch(r => fn(r.data, r.status, r.headers, r.config)); return p; };
  return p;
}

// Simulate standard .then()
function fakeHttpStandard() {
  return Promise.resolve({ data: {id:1}, status: 200, statusText: 'OK', headers: {}, config: {} });
}

// Legacy
fakeHttpLegacy().success(function(data, status, headers, config) {
  console.log('LEGACY .success — data:', data, '| status:', status);
});

// Standard
fakeHttpStandard().then(function(response) {
  console.log('STANDARD .then — data:', response.data, '| status:', response.status, '| statusText:', response.statusText);
});

// Chaining test — does legacy chain correctly?
const chained = fakeHttpLegacy().then(r => { console.log('CHAIN after legacy — response object:', r); });
```

